/**
 * SAML Relying Party GET handler (samlgw2)
 *
 * Gets a single RP's details from samlgw2 customer data + DynamoDB SP info.
 */

import { GetItemCommand, QueryCommand } from '@aws-sdk/client-dynamodb';
import {
  createSamlGw2ClientFromEnv,
  buildSamlgw2ItorgId,
} from '../samlgw2-client/index.mjs';

async function getTenantInfo(tenantId, dynamodb, tenantTable) {
  const result = await dynamodb.send(new QueryCommand({
    TableName: tenantTable,
    KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
    ExpressionAttributeValues: {
      ':id': { S: `TENANT#${tenantId}` },
      ':sk_prefix': { S: 'TENANT#' },
    },
  }));
  if (!result.Items || result.Items.length === 0) return null;
  const item = result.Items[0];
  return {
    orgId: item.org_id?.S,
    userPoolId: item.userpool?.S,
    samlClientId: item.samlClientId?.S,
  };
}

async function getSamlgw2ItorgId(tenantOrgId, dynamodb, tenantTable) {
  try {
    const result = await dynamodb.send(new QueryCommand({
      TableName: tenantTable,
      KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
      ExpressionAttributeValues: {
        ':id': { S: `ORG#${tenantOrgId}` },
        ':sk_prefix': { S: 'ORG#' },
      },
      ProjectionExpression: 'samlgw2_itorg_id',
    }));
    const stored = result.Items?.[0]?.samlgw2_itorg_id?.S;
    if (stored) return stored;
  } catch (e) {
    console.log('Failed to query org:', e.message);
  }
  return buildSamlgw2ItorgId(process.env.ACCOUNT_ID, tenantOrgId);
}

export const getResData = async (rpName, dynamodb, tenantId, tenantTable, spInfoTable) => {
  if (!rpName) {
    return { id: rpName };
  }

  // Get tenant info to resolve org → itorg
  const tenantInfo = await getTenantInfo(tenantId, dynamodb, tenantTable);
  if (!tenantInfo?.orgId) {
    return { id: rpName, error: 'Tenant has no org' };
  }

  const itorgId = await getSamlgw2ItorgId(tenantInfo.orgId, dynamodb, tenantTable);
  const customerName = tenantId.toLowerCase();

  // Get customer data from samlgw2
  let rpConfig = null;
  try {
    const samlgw2 = createSamlGw2ClientFromEnv();
    const customerData = await samlgw2.getCustomer(itorgId, customerName);
    const relyingParties = customerData?.doc?.relying_parties || {};
    rpConfig = relyingParties[rpName];
  } catch (e) {
    console.log('Failed to fetch from samlgw2:', e.message);
  }

  // Get SP info from DynamoDB
  let spInfo = null;
  try {
    const spInfoRes = await dynamodb.send(new GetItemCommand({
      TableName: spInfoTable,
      Key: { id: { S: `#SAML#${rpName}` } },
    }));
    if (spInfoRes?.Item?.id) {
      spInfo = {
        logoUrl: spInfoRes.Item.logoUrl?.S || '',
        serviceUrl: spInfoRes.Item.serviceUrl?.S || '',
        released: spInfoRes.Item.released?.BOOL || false,
        template: spInfoRes.Item.template?.S || 'custom',
        idpMetadataUrl: spInfoRes.Item.idpMetadataUrl?.S || '',
        callbackUrl: spInfoRes.Item.callbackUrl?.S || '',
      };
    }
  } catch (e) {
    console.log('Failed to get spInfo from DynamoDB:', e.message);
  }

  // Build IDP metadata URL
  const samlgw2 = createSamlGw2ClientFromEnv();
  const idpMetadataUrl = samlgw2.getIdpMetadataUrl(itorgId, customerName, rpName);
  const callbackUrl = samlgw2.getOidcCallbackUrl(itorgId, customerName, rpName);

  return {
    id: rpName,
    rpName,
    name: rpConfig?.display_name || spInfo?.name || rpName,
    metadataUrl: rpConfig?.sp?.metadata_url || '',
    serviceUrl: spInfo?.serviceUrl || rpConfig?.login_url || '',
    logoUrl: spInfo?.logoUrl || rpConfig?.logo_url || '',
    released: spInfo?.released || false,
    template: spInfo?.template || 'custom',
    idpMetadataUrl,
    callbackUrl,
    // Include samlgw2 config details for editing
    claim_mappings: rpConfig?.claim_mappings || null,
    saml: rpConfig?.saml || null,
    sp_metadata_url: rpConfig?.sp?.metadata_url || '',
    display_name: rpConfig?.display_name || '',
    login_url: rpConfig?.login_url || '',
    logo_url: rpConfig?.logo_url || '',
  };
};

export default getResData;
